import{_ as s,H as e,f as n,i}from"./chunks/framework.CzroR0Ng.js";const g=JSON.parse('{"title":"vibecoding 开发流程","description":"","frontmatter":{},"headers":[],"relativePath":"guide/vibecoding开发流程.md","filePath":"guide/vibecoding开发流程.md"}'),t={name:"guide/vibecoding开发流程.md"};function p(o,a,l,d,c,r){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="vibecoding-开发流程" tabindex="-1">vibecoding 开发流程 <a class="header-anchor" href="#vibecoding-开发流程" aria-label="Permalink to &quot;vibecoding 开发流程&quot;">​</a></h1><h2 id="_01-需求梳理-简要概述需求" tabindex="-1">01 需求梳理（简要概述需求） <a class="header-anchor" href="#_01-需求梳理-简要概述需求" aria-label="Permalink to &quot;01 需求梳理（简要概述需求）&quot;">​</a></h2><p>先想清楚再动手：功能概述、用户场景、核心页面、数据与使用方式。</p><ul><li>功能概述：要实现什么功能；把核心功能逐条列出，避免笼统描述。</li><li>用户场景：谁会在什么情况下使用产品；产品解决什么问题。</li><li>核心页面：有哪些主要页面；每个页面分别承载什么功能。</li><li>数据与使用：数据存在哪里、给谁用、是否需要备份、是否有权限要求。</li></ul><p><strong>手写产出：</strong> <code>产品需求.md</code></p><h2 id="_02-prd-文档-给-ai-写-规范描述" tabindex="-1">02 PRD 文档（给 AI 写，规范描述） <a class="header-anchor" href="#_02-prd-文档-给-ai-写-规范描述" aria-label="Permalink to &quot;02 PRD 文档（给 AI 写，规范描述）&quot;">​</a></h2><p>让 AI 生成产品文档，重点看框架图，反复确认后再进入下一步。</p><p><strong>提示词：</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请帮我在PRDS文件夹内创建一份产品需求文档PRD.md，包含以下内容：</span></span>
<span class="line"><span>第一：产品概述，一句话说明产品是什么，解决什么问题；</span></span>
<span class="line"><span>第二：目标用户，谁会使用这个产品；</span></span>
<span class="line"><span>第三：核心功能清单，按优先级排列，标出P0、P1、P2；</span></span>
<span class="line"><span>第四：页面结构，列出所有主要页面及其功能，请基于我之前提供的需求梳理以及这份草图来撰写，另外所有主要页面先用Markdown画一个框架图。</span></span></code></pre></div><p><strong>AI 生成：</strong> <code>PRD.md</code></p><h2 id="_03-设计-demo-结合前面规范设计-有问题就沟通修改" tabindex="-1">03 设计 Demo（结合前面规范设计，有问题就沟通修改） <a class="header-anchor" href="#_03-设计-demo-结合前面规范设计-有问题就沟通修改" aria-label="Permalink to &quot;03 设计 Demo（结合前面规范设计，有问题就沟通修改）&quot;">​</a></h2><p>先做静态 HTML 前端页面，用于确认布局、配色、交互是否符合预期。</p><p><strong>提示词：</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请结合这张风格参考图，参考其中的设计风格和配色，以及前面的PRD和草图，做一个静态demo展示主要页面和最核心的状态，能够呈现产品的设计配色以及功能模块，不用做具体的逻辑。</span></span></code></pre></div><p><strong>Demo 反馈模板：</strong></p><ol><li>我在哪个页面；</li><li>我发现了什么问题；</li><li>我希望怎么改正（我的预期是什么）。</li></ol><h3 id="ui-设计文档-用于规范后续-ai-开发时的前端样式" tabindex="-1">UI 设计文档（用于规范后续 AI 开发时的前端样式） <a class="header-anchor" href="#ui-设计文档-用于规范后续-ai-开发时的前端样式" aria-label="Permalink to &quot;UI 设计文档（用于规范后续 AI 开发时的前端样式）&quot;">​</a></h3><p>产品后续开发会不断新开窗口；每次接手的 AI 都不了解之前实现，设计规范用于保证统一风格。</p><ul><li>新窗口 = 新 AI：每次新开对话，接手 AI 没有上下文记忆，不知道之前的实现逻辑。</li><li>风格必须统一：没有规范约束时，不同 AI 的页面风格、配色、交互会不一致。</li><li>规范即交接：一份设计规范文档，就是给下一个接手 AI 的规范手册。</li></ul><p><strong>提示词：</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请根据我们刚才制作的demo整理一份UI设计规范文档，包括配色方案，字体规范，字体层级，卡片样式，组件样式，按钮样式等待，用来规范后续的开发，确保第一个版本和demo的样式一致。</span></span></code></pre></div><p><strong>AI 生成：</strong> <code>UI设计规范.md</code></p><h2 id="_04-分步开发" tabindex="-1">04 分步开发 <a class="header-anchor" href="#_04-分步开发" aria-label="Permalink to &quot;04 分步开发&quot;">​</a></h2><p>制定详细计划，逐步推进；每一步完成后新开对话窗口继续。</p><p><strong>提示词：</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请根据PRD文档和静态demo帮我制定一份详细的开发计划，要求如下：</span></span>
<span class="line"><span>第一：把整个开发任务拆分成独立步骤，每一步完成一个可验证的功能模块；</span></span>
<span class="line"><span>第二：每一步标注要实现的功能、涉及的文件和完成标准怎么判断这一步做完了；</span></span>
<span class="line"><span>第三：按依赖关系排列顺序 先基础功能再高级功能；</span></span>
<span class="line"><span>第四：每一步描述要足够完整，让新的AI会话能独立理解，因为每步会新开会话；</span></span>
<span class="line"><span>第五：最后附一个项目技术栈总览，用了什么框架库和部署方式。</span></span></code></pre></div><p><strong>AI 生成：</strong> <code>开发计划.md</code></p><p>然后进行开发。</p><h2 id="_05-部署上线" tabindex="-1">05 部署上线 <a class="header-anchor" href="#_05-部署上线" aria-label="Permalink to &quot;05 部署上线&quot;">​</a></h2><p>使用 <code>GitHub + 上线工具</code> 的组合，完成：推送代码、拉取构建、公开访问。</p>`,30)])])}const u=s(t,[["render",p]]);export{g as __pageData,u as default};
